const t=JSON.parse('{"key":"v-6df38b7e","path":"/learningNote/Computer_Network/UDP%E6%A0%A1%E9%AA%8C%E5%92%8C.html","title":"如何计算UDP校验和","lang":"zh-CN","frontmatter":{"title":"如何计算UDP校验和","category":["Computer","Network","basic"]},"headers":[{"level":2,"title":"如何构造校验和checksum？","slug":"如何构造校验和checksum","link":"#如何构造校验和checksum","children":[]},{"level":2,"title":"如何对传入的UDP进行校验？","slug":"如何对传入的udp进行校验","link":"#如何对传入的udp进行校验","children":[]}],"git":{"createdTime":1699252784000,"updatedTime":1699252784000,"contributors":[{"name":"Jeacson_Snake","email":"Jeacson_Snake@outlook.com","commits":1}]},"readingTime":{"minutes":2.89,"words":867},"filePathRelative":"learningNote/Computer_Network/UDP校验和.md","localizedDate":"2023年11月6日","excerpt":"<h2> 如何构造校验和checksum？</h2>\\n<p>checksum 的构造方法比较简单，但是计算比较麻烦：将需要发送的 16-bit 二进制源数据两两相加，取从右往左数共十六位数，如果有多的位数就把该位数移到最低位再相加。如此反复将所有需要发送的数据相加完毕后对它作反码，即将这十六位数的1置0，0置1。</p>\\n<p>具体需要的数据以下列的表格作为例子：</p>\\n<table>\\n<tbody>\\n<tr>\\n<td colspan=\\"4\\">发送端IP地址</td>\\n</tr>\\n<tr>\\n<td colspan=\\"4\\">接收端IP地址</td>\\n</tr>\\n<tr>\\n<td colspan=\\"2\\">UDP协议对应数(17)</td>\\n<td colspan=\\"2\\">UDP网段总长度</td>\\n</tr>\\n<tr>\\n<td colspan=\\"2\\">UDP源端口号</td>\\n<td colspan=\\"2\\">UDP目的端口号</td>\\n</tr>\\n<tr>\\n<td colspan=\\"2\\">UDP网段总长度</td>\\n<td colspan=\\"2\\"><strong>校验和数值(在这里设为0)</strong></td>\\n</tr>\\n<tr>\\n<td>数据</td>\\n<td>数据</td>\\n<td>数据</td>\\n<td>数据</td>\\n</tr>\\n<tr>\\n<td>数据</td>\\n<td>数据</td>\\n<td>数据</td>\\n<td>数据</td>\\n</tr>\\n<tr>\\n<td>数据</td>\\n<td>数据</td>\\n<td>数据</td>\\n<td>数据</td>\\n</tr>\\n<tr>\\n<td>数据</td>\\n<td>数据</td>\\n<td>数据</td>\\n<td>数据</td>\\n</tr>\\n<tr>\\n<td colspan=\\"4\\">......</td>\\n</tr>\\n<tr>\\n<td>数据</td>\\n<td>数据</td>\\n<td>数据</td>\\n<td>(后置位补零，有需要就加，否则不加)</td>\\n</tr>\\n</tbody>\\n</table>"}');export{t as data};
